SELECT
    d.department_name,
    AVG(TONUMBER(e.salary)) AS avg_salary,
    COUNT(e.employee_id) AS employee_count,
    COALESCE(d.`type`, 'Unknown') AS dept_type
FROM `hr_company`.`hr_scope`.`employees` AS e
JOIN `hr_company`.`hr_scope`.`departments` AS d
